BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?contribType ?contribName WHERE {
  ?budgetElem rdf:type ?budgetType ;
              vocab:NamedElement_name "Pupil Alignment Error Budget" ;
              (vocab:Element_ownedElement|vocab:Package_packagedElement|vocab:Namespace_ownedMember|vocab:Namespace_member) ?contrib .

  ?contrib rdf:type ?contribType .
  ?contrib vocab:NamedElement_name ?contribName .

  FILTER(
    CONTAINS(LCASE(STR(?contribName)), LCASE("error analysis")) ||
    CONTAINS(LCASE(STR(?contribName)), LCASE("alignment"))
  )
}
ORDER BY ?contribName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?contrib ?contribType ?contribName ?rel WHERE {
  ?budgetElem vocab:NamedElement_name "Pupil Alignment Error Budget" .

  {
    ?budgetElem vocab:Element_ownedElement ?contrib .
    BIND("Element_ownedElement" AS ?rel)
  }
  UNION
  {
    ?budgetElem vocab:Package_packagedElement ?contrib .
    BIND("Package_packagedElement" AS ?rel)
  }
  UNION
  {
    ?budgetElem vocab:Namespace_ownedMember ?contrib .
    BIND("Namespace_ownedMember" AS ?rel)
  }
  UNION
  {
    ?budgetElem vocab:Namespace_member ?contrib .
    BIND("Namespace_member" AS ?rel)
  }

  ?contrib rdf:type ?contribType .
  OPTIONAL { ?contrib vocab:NamedElement_name ?contribName . }
}
ORDER BY ?rel ?contribName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?budgetElem ?budgetName ?child ?childType ?childName ?via WHERE {
  ?budgetElem vocab:NamedElement_name "Pupil Alignment Error Budget" .
  ?budgetElem rdf:type ?budgetType .
  BIND(?budgetType AS ?budgetType2)
  BIND("budget" AS ?budgetNameDummy)
  BIND("Pupil Alignment Error Budget" AS ?budgetName)

  {
    ?budgetElem vocab:Element_ownedElement ?child .
    BIND("Element_ownedElement" AS ?via)
  }
  UNION
  {
    ?child vocab:Element_owner ?budgetElem .
    BIND("Element_owner^" AS ?via)
  }
  UNION
  {
    ?budgetElem vocab:Package_packagedElement ?child .
    BIND("Package_packagedElement" AS ?via)
  }
  UNION
  {
    ?child vocab:PackageableElement_owningPackage ?budgetElem .
    BIND("PackageableElement_owningPackage" AS ?via)
  }
  UNION
  {
    ?budgetElem vocab:Namespace_member ?child .
    BIND("Namespace_member" AS ?via)
  }
  UNION
  {
    ?child vocab:NamedElement__namespaceOfMember ?budgetElem .
    BIND("NamedElement__namespaceOfMember" AS ?via)
  }
  UNION
  {
    ?budgetElem vocab:Namespace_ownedMember ?child .
    BIND("Namespace_ownedMember" AS ?via)
  }
  UNION
  {
    ?child vocab:NamedElement_namespace ?budgetElem .
    BIND("NamedElement_namespace" AS ?via)
  }

  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?budgetElem ?child ?predicate ?childName WHERE {
  ?budgetElem vocab:NamedElement_name "Pupil Alignment Error Budget" .
  ?budgetElem ?predicate ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?predicate ?child ?childType ?childName WHERE {
  ?budgetElem vocab:NamedElement_name ?budgetName .
  FILTER(CONTAINS(LCASE(STR(?budgetName)), LCASE("pupil%20alignment%20error%20budget")))

  ?budgetElem ?predicate ?child .
  OPTIONAL { ?child rdf:type ?childType . }
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }

  FILTER(
    ?childName != "" ||
    ?childType != ""
  )
}
ORDER BY ?predicate
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?assoc ?assocName WHERE {
  ?budgetElem vocab:NamedElement_name "Pupil Alignment Error Budget" .
  ?budgetElem vocab:Element_ownedElement ?assoc .
  ?assoc rdf:type vocab:association .
  OPTIONAL { ?assoc vocab:NamedElement_name ?assocName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  ?budgetElem vocab:NamedElement_name ?budgetName .
  FILTER(CONTAINS(LCASE(STR(?budgetName)), LCASE("pupil%20alignment%20error%20budget")))
  ?budgetElem vocab:Element_ownedElement ?child .

  OPTIONAL { ?child rdf:type ?childType . }
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25
